INSERT INTO `catalog_product_entity_text` VALUES (1,75,0,1,'Áo mưa đoàn bảo vệ bạn khỏi thời tiết mưa nắng thất thường trong những chuyến leo núi, đảm bảo trải nghiệm ngoài trời an toàn trong thời tiết khắc nghiệt nhất.'),(2,75,0,2,'Ủng nilon (loại mới) giá chỉ 10k rẻ nhất tại WeTrek. Ủng bằng nilon chống nước tuyệt đối. Nhỏ gọn, tiện lợi khi đi du lịch, đi phượt. Liên hệ: 02873051988.'),(3,75,0,3,'Tính năng nhanh khô không để lại mồ hôi, thoáng khí và rất nhẹ phù hợp với các hoạt động dã ngoại ngoài trời hay các công việc hay phải di chuyển nhiều vào thời tiết nắng nóng nhờ tới công nghệ giúp di chuyển và phát tán hơi ẩm ra khỏi cơ thể một cách nhanh nhất, giữ cho người dùng luôn thoải mái trong suốt quá trình vận động.'),(4,75,0,4,'Áo mưa balo 30 - 50L Raincover - 7692  được làm từ chất liệu 100% Polyester chống nước rất tốt, bề mặt nhẵn bóng khó bám bẩn và dễ dàng làm sạch. Phù hợp sử dụng cho Balo leo núi có thể tích từ 30-50L. Đây là phụ kiện không thể thiếu cho chiếc balo của bạn.'),(5,75,0,5,'Quần mau khô Gothiar thuận tiện cho những hoạt động như leo núi, đi bộ, lội suối, du lịch dã ngoại, hoạt động ngoài trời.'),(6,75,0,6,'Làm bằng chất liệu vải nhanh khô với công nghệ đạt chuẩn UV50+ (hay còn gọi là tia cực tím) giúp cho bạn an toàn hơn khi đi ngoài trời.'),(7,75,0,7,'Tính năng nhanh khô không để lại mồ hôi, thoáng khí và rất nhẹ phù hợp với các hoạt động dã ngoại ngoài trời hay các công việc hay phải di chuyển nhiều vào thời tiết nắng nóng nhờ tới công nghệ giúp di chuyển và phát tán hơi ẩm ra khỏi cơ thể một cách nhanh nhất, giữ cho người dùng luôn thoải mái trong suốt quá trình vận động.'),(8,75,0,8,'Tính năng nhanh khô không để lại mồ hôi, thoáng khí và rất nhẹ phù hợp với các hoạt động dã ngoại ngoài trời hay các công việc hay phải di chuyển nhiều vào thời tiết nắng nóng nhờ tới công nghệ giúp di chuyển và phát tán hơi ẩm ra khỏi cơ thể một cách nhanh nhất, giữ cho người dùng luôn thoải mái trong suốt quá trình vận động.'),(9,75,0,9,'Áo khoác gió 2 lớp nam Gothiar Windproof Jacket Nature có thiết kế 2 lớp với mặt ngoài được dệt từ vải Gore-Tex, mặt trong được tráng lớp PU giúp cho việc chống thấm được tốt và giữ ấm cho cơ thể. Trọng lượng nhẹ có thể gấp gọn một cách tiện lợi.'),(10,75,0,10,'Áo thun dã ngoại Gothiar Active được thiết kế đặc biệt để đáp ứng nhu cầu của những người yêu thích hoạt động thể thao và dã ngoại. Với chất liệu polyester chất lượng cao, thấm hút mồ hôi tốt và thoáng khí, giúp bạn thoải mái trong mọi hoạt động.'),(11,75,0,11,'Giày leo núi cổ thấp Clorts Trekking Shoes 3D033E với công nghệ chống thấm UNEEBTEX, đế cao su chống trượt, thấm hút mồ hôi nhanh chóng và hấp thụ sốc. Thân giày được làm từ da lộn và vải lưới tạo độ thoáng khí. Mũi giày làm từ cao su cứng giúp bảo vệ đôi chân khỏi va đập.'),(12,75,0,12,'Đế giày leo núi nữ cổ cao Humtto Hiking Shoes 290015B-1 mềm mại và thông thoáng, độ bền cao cùng thiết kế mũi giày chống va đập, bảo vệ tránh chấn thương khi vận động.'),(13,75,0,13,'Đế giày mềm mại và thông thoáng, độ bền cao cùng thiết kế mũi giày chống va đập, bảo vệ tránh chấn thương khi vận động.'),(14,75,0,14,'Đế giày mềm mại và thông thoáng, độ bền cao cùng thiết kế mũi giày chống va đập, bảo vệ tránh chấn thương khi vận động.'),(15,75,0,15,'Khám phá cuộc phiêu lưu ngoại trời với giày Humtto Hiking Men Shoes 110609A-2. Thiết kế linh hoạt, chống nước mạnh mẽ, và đế êm dẻo giúp bạn tự tin vượt qua mọi địa hình. Đi bộ đường dài, leo núi, hay trekking - sự thoải mái và bảo vệ tối đa đều là của riêng bạn. Đặt hàng ngay để trải nghiệm cuộc hành trình mới với đôi giày đa dụng này'),(16,75,0,16,'Giày leo núi nữ cổ thấp Humtto Hiking Shoes 140503B-3 có chất liệu được làm từ da thật với độ bền cao. Đế ngoài cao su với công nghệ đế trợ lực và chống trơn trượt. Phần mũi giày thiết kế đặc biệt giúp bảo vệ các ngón chân tốt hơn, tránh bị tổn thương khi vận động. Giày phù hợp sử dụng cho các hoạt động thể thao dã ngoại ngoài trời, leo núi, đi bộ đường dài...'),(17,75,0,17,'Giày leo núi cổ thấp Humtto 120562A-3 với đế giày mềm mại và thông thoáng, độ bền cao cùng thiết kế mũi giày chống va đập, bảo vệ tránh chấn thương khi vận động.'),(18,75,0,18,'Đế giày mềm mại và thông thoáng, độ bền cao cùng thiết kế mũi giày chống va đập, bảo vệ tránh chấn thương khi vận động.'),(19,75,0,19,'Đế giày leo núi cổ thấp Humtto Hiking Shoes 140121A-3 mềm mại và thông thoáng, độ bền cao cùng thiết kế mũi giày chống va đập, bảo vệ tránh chấn thương khi vận động.'),(20,75,0,20,'Giày leo núi cổ thấp nữ Humtto Hiking Shoes 140134B-2 màu đen, chống nước, kiểu dáng sneaker hiện đại với dây giày ẩn mang đến thiết kế gọn gàng và khả năng điều chỉnh vừa vặn với lòng bàn chân, mang đến sự thoải mái tối ưu. Phần mũi giày chắc chắn, chống va đập giúp bảo vệ ngón chân. Đế giày với 2 lớp: lớp lót EVA thông thoáng, hạn chế gây mùi khó chịu và phần đế từ chất liệu cao su có khả năng chịu lực lớn, độ bền cao.'),(21,75,0,21,'Mũ lưỡi trai Cờ Đỏ Sao Vàng giá chỉ 18K tại WeTrek mang phong cách cá tính và thể hiện lòng yêu nước ngày càng được ưu chuộng. Mũ được làm từ chất liệu vải mềm, thoáng, bền và giữ form.'),(22,75,0,22,'Mũ rộng vành mau khô Comfort Sun Hat được làm từ chất liệu 100% Polyester, chống tia UVA, UVB bảo vệ làn da khỏi ánh nắng mặt trời. Lớp lưới dày dặn, thoáng khí và trang bị công nghệ thoát hơi nhanh giúp đầu luôn khô ráo và thoáng mát trong các hoạt động ngoài trời. Công nghệ chống tia UV (UPF 50+) ngăn chặn tác động tiêu cực của tia UV đến da và tóc, mang lại sự an tâm trong khi ra nắng. Ghé thăm để mua Mũ rộng vành mau khô Comfort Sun Hat với chất lượng và tính năng tốt nhất.'),(23,75,0,23,'Được làm từ chất liệu 100% Polyester có khả năng chống tia UVA, UVB bảo vệ làn da của bạn khỏi ánh nắng mặt trời.Lớp lưới dày dặn, thoáng khí.'),(24,75,0,24,'Được làm từ chất liệu 100% Polyester có khả năng chống tia UVA, UVB bảo vệ làn da của bạn khỏi ánh nắng mặt trời.Lớp lưới dày dặn, thoáng khí.'),(25,75,0,25,'Với thiết kế độc đáo có thể linh hoạt tháo lắp phần che gáy giúp sản phẩm thay đổi tùy điều kiện sử dụng. Thêm nữa mũ có phần lưới giúp thoáng khí, cực kỳ thoải mái và dễ chịu khi đi treking, nhất là trong thời tiết nắng gắt.'),(26,75,0,26,'Mũ lưỡi trai gấp gọn Aonijie Fast Dry Sun Protection E4107 nhẹ nhàng và linh hoạt, dễ dàng gấp gọn khi không sử dụng'),(27,75,0,27,'Dòng mũ vành rộng được làm từ 2 lớp dày dặn: Lớp ngoài là 100% Nylon mềm mại, thấm hút mồ hôi và an toàn cho da.'),(28,75,0,28,'Mũ lưỡi trai Buff Visor R - Sural Multi - 9503 Dành cho các hoạt động thể thao ngoài trời như nón chạy bộ, nón chơi goft hay tennis, dã ngoại, chèo thuyền, chạy bộ, đạp xe hoặc chạy xe máy, bóng chuyền bãi biển...khả năng chống 98% tia UV.'),(29,75,0,29,'Mũ lưỡi trai Buff 5 Panel Go Cap Domus chính hãng. Thiết kế nhẹ, thoáng khí, UPF 50 chống nắng, thấm hút mồ hôi. Chất liệu tái chế thân thiện môi trường. Phù hợp chạy bộ, tập luyện và sử dụng hàng ngày. Mua ngay!'),(30,75,0,30,'Mũ lưỡi trai Buff Visor R - Solid Black - 9502 Dành cho các hoạt động thể thao ngoài trời như nón chạy bộ, nón chơi goft hay tennis, dã ngoại, chèo thuyền, chạy bộ, đạp xe hoặc chạy xe máy, bóng chuyền bãi biển...khả năng chống 98% tia UV.'),(31,75,0,31,'Túi ngủ Snowline Sleeping Soft Warm 1000 Crazy Idea CRH5USB002 Ruột 1000g Micro Silk Fiber siêu ấm, lót Velboa mềm mại. Nhiệt độ an toàn 14 độ. Dễ dàng kết nối đôi, nén gọn 1.7kg.'),(32,75,0,32,'Túi ngủ Ryder D1001 được dệt từ polyester 190T với các đặc tính ưu việt như dẻo dai bền sợi, trọng lượng nhẹ, chịu mài mòn tốt, chịu ít ảnh hưởng của độ ẩm.'),(33,75,0,33,'Túi ngủ Naturehike Sleeping Bag With Hood  NH20MSD07 với chất liệu vải thân thiện, tránh kích ứng da cùng với lớp bông dày đảm bảo giấc ngủ ngon của người sử dụng trong thời tiết lạnh giá.'),(34,75,0,34,'Túi ngủ Ryder Envelope Sleeping Bag D1002 Orange- 7483 được làm từ chất liệu Polyester chống thấm nước, bền, dai, giữ nhiệt tốt hơn và dễ dàng vệ sinh.'),(35,75,0,35,'Dòng túi ngủ đơn LW180 được làm lại với một nền tảng chất liệu cao cấp hơn. Cảm giác sử dụng ấm áp và êm ái hơn với chất liệu hoàn thiện từ sợi Nylon – bông lót Cotton – lớp bên trong từ Pongee.'),(36,75,0,36,'Túi ngủ mùa đông Ryder D1005 có thiết kế dáng con nhộng với lớp ngoài chống thấm và cách nhiệt tối đa, phần lõi bông giữ nhiệt rất tốt. Phù hợp sử dụng ở những nơi có nhiệt độ thấp.'),(37,75,0,37,'Túi ngủ nỉ Northpeak Sleeping Bag - 7855 được làm từ chất liệu nỉ mềm mịn, giữ nhiệt tốt, trọng lượng nhẹ, đi kèm túi đựng có dây xách tiện lợi.'),(38,75,0,38,'Túi ngủ mùa đông Ryder D1005 có thiết kế dáng con nhộng với lớp ngoài chống thấm và cách nhiệt tối đa, phần lõi bông giữ nhiệt rất tốt.'),(39,75,0,39,'Chất liệu êm ái và thiết kế 3 lớp thoải mái nhất khi sử dụng, thuận tiện khi vệ sinh bằng máy giặt.'),(40,75,0,40,'Túi ngủ Naturehike Envelope Washable NH20MSD02 chất liệu êm ái và thiết kế 3 lớp thoải mái nhất khi sử dụng, thuận tiện khi vệ sinh bằng máy giặt.'),(41,75,0,41,'Bình nước giữ nhiệt Ryder 800ml được làm từ nhựa polycarbonate đảm bảo vệ sinh và an toàn cho người sử dụng. Rất tiện dụng cho hoạt động ngoài trời và những hoạt động hàng ngày.'),(42,75,0,42,'Bình nước 850ml Ryder Polycarbonate Bottle N0003 - 1987 được làm từ nhựa polycarbonate đảm bảo vệ sinh và an toàn cho người sử dụng. Rất tiện dụng cho hoạt động ngoài trời và những hoạt động hàng ngày.'),(43,75,0,43,'Túi nước dã ngoại RyDer 15L C4006 là túi được thiết kế các nếp gấp, giúp bạn có thể gấp gọn túi sau khi sử dụng. Nắp bình được thiết kế gắn với vòi để tiện sử dụng. Bạn thoải mái mang nước để sử dụng cho chuyến đi của mình.'),(44,75,0,44,'Túi nước RyDer 20L C4007 được thiết kế hình hộp gấp, giúp bạn có thể gấp gọn túi sau khi sử dụng. Túi được thiết kế vòi nước ở ngay nắp túi, bạn dễ dàng sử dụng nước trong bình mà không cần dùng sức đổ.'),(45,75,0,45,'Xô gấp siêu nhẹ 10L Ryder 500D PVC Folding Bucket C4001 - 6679 là sản phẩm đựng nước dung tích lớn, siêu nhẹ có khả năng gấp lại gọn gàng.'),(46,75,0,46,'Bình nước 500ml Ryder Polycarbonate Bottle N0001 - 1985 được làm từ nhựa polycarbonate, đảm bảo vệ sinh và an toàn cho người sử dụng, rất tiện dụng cho hoạt động ngoài trời và những hoạt động hàng ngày.'),(47,75,0,47,'Túi nước dã ngoại RyDer 10L C4009 là túi được thiết kế các nếp gấp, giúp bạn có thể gấp gọn túi sau khi sử dụng. Bạn thoải mái mang nước để sử dụng cho chuyến đi của mình và tiện dụng gấp gọn, cất giữ khi không dùng nữa.'),(48,75,0,48,'Vỏ cao su giữ nhiệt bình nước 600ml Ryder Water Bottle Insulated Cover N2001 - 1983 được làm từ nhựa cao cấp, chống trầy, chống bám bẩn và bền màu. Thiết kế 2 lớp và nắp xoay kín giúp giữ nhiệt các loại đồ uống của bạn lâu hơn khi đi cắm trại dã ngoại.'),(49,75,0,49,'Cốc siêu nhẹ Naturehike Lightweight Durable Titanium NH20CJ005 với chất liệu titanium siêu bền là phụ kiện thích hợp trong hành trang cho những chuyến du lịch, dã ngoại'),(50,75,0,50,'Bình nước giữ nhiệt 946ml Hydro Flask Wide Flex Cap 32 OZ W32BTS với nắp Flex Sip™ giữ nước nóng đến 12 giờ và lạnh đến 24 giờ. Chất liệu thép không gỉ 18/8 bền bỉ, miệng rộng cho đá viên dễ dàng, lớp phủ Color Last™ chống đọng hơi nước.'),(51,75,0,51,'Áo mưa balo 20-30L Ryder Rucksack Raincover S F1001 - 6698 là trang bị không thể thiếu dành cho những người đam mê du lịch khi tới những nơi có khí hậu mưa và ẩm ướt.'),(52,75,0,52,'Áo mưa balo 30-50L Ryder Rucksack Raincover M F1002 - 6699 là trang bị không thể thiếu dành cho những người đam mê du lịch khi tới những nơi có khí hậu mưa và ẩm ướt.'),(53,75,0,53,'Đẹp và tiện lợi khi sử dụng, có khả năng chống thấm nước tốt, phù hợp sử dụng đi cắm trại qua đêm, dã ngoại ngoài trời, du lịch'),(54,75,0,54,'Balo leo núi 25L Senterlan Speed Air S8358 được làm từ 100% polyester bền, nhẹ, chống chầy xước, thiết kế gọn nhẹ, chắc chắn là một trang bị du lịch hoàn hảo cho các chuyến đi leo núi, cắm trại dã ngoại.'),(55,75,0,55,'Ba lô leo núi 70+10L Ryder Backpack F0003 - 6690 làm từ chất liệu vải nylon độ bền cao, khung trợ lực tránh mỏi lưng, phù hợp leo núi, dã ngoại.'),(56,75,0,56,'Balo leo núi Senterlan Adventure 4