INSERT INTO `vendor_news_rss_cache` VALUES (2801,'https://vnexpress.net/khach-bay-sun-phuquoc-airways-duoc-tang-buffet-va-ve-uu-tien-tai-ba-na-5082370.html','Khách bay Sun PhuQuoc Airways được tặng buffet và vé ưu tiên tại Bà Nà','Hành khách bay Sun PhuQuoc Airways (SPA) đến Đà Nẵng mua vé cáp treo Bà Nà sẽ nhận ngay combo buffet và vé ưu tiên 680.000 đồng, dịp Lễ hội pháo hoa quốc tế 2026.','https://vnexpress.net/khach-bay-sun-phuquoc-airways-duoc-tang-buffet-va-ve-uu-tien-tai-ba-na-5082370.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/05/tau-bay-spa-ha-canh-da-nang-17-3353-1438-1780643738.jpg?w=680&h=408&q=100&dpr=1&fit=crop&s=zgNX_31O1p39PSGGud79yw','2026-06-05 15:08:40'),(2802,'https://vnexpress.net/loat-hoat-dong-he-cho-gia-dinh-tai-khu-nghi-duong-o-cam-ranh-5081984.html','Loạt hoạt động hè cho gia đình tại khu nghỉ dưỡng ở Cam Ranh','Radisson Blu Resort Cam Ranh giới thiệu chuỗi trải nghiệm \"Blu Ocean Summer\", mang đến hành trình nghỉ dưỡng kết hợp vui chơi, khám phá văn hóa địa phương dành cho cả gia đình dịp hè.','https://vnexpress.net/loat-hoat-dong-he-cho-gia-dinh-tai-khu-nghi-duong-o-cam-ranh-5081984.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/05/canvas-painting-1780623562-6248-1780624017.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=dfEgrTezZFXDgoh96e7Avg','2026-06-05 15:08:40'),(2803,'https://vnexpress.net/cap-khach-tay-chi-duong-cho-nguoi-den-du-lich-viet-nam-5081591.html','Cặp khách Tây \'chỉ đường\' cho người đến du lịch Việt Nam','Hai du khách Liam và Sarah đã lập kênh thông tin Two Peas Abroad để trực tiếp hướng dẫn người nước ngoài trải nghiệm du lịch Việt Nam sau hơn ba năm sinh sống như người bản địa.','https://vnexpress.net/cap-khach-tay-chi-duong-cho-nguoi-den-du-lich-viet-nam-5081591.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/03/two-peas-abroad-mekong-delta-1-4116-6852-1780475568.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=J3_7FYXrXUQ3z150bmyfXg','2026-06-05 15:08:40'),(2804,'https://vnexpress.net/vietrantour-mo-ban-1-000-suat-tour-giam-gia-5082014.html','Vietrantour mở bán 1.000 suất tour giảm giá','Vietrantour mở bán 1.000 suất tour trong nước và quốc tế giảm giá cho khách thanh toán trong tháng 6, áp dụng tất cả hành trình khởi hành linh hoạt suốt năm.','https://vnexpress.net/vietrantour-mo-ban-1-000-suat-tour-giam-gia-5082014.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/04/vtt2-1780563464-5452-1780563530.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=M2tKSD9WebOLsZZo33oPBQ','2026-06-05 15:08:40'),(2805,'https://vnexpress.net/sun-group-gioi-thieu-diem-den-viet-tai-hoi-cho-du-lich-seoul-5081847.html','Sun Group giới thiệu điểm đến Việt tại hội chợ du lịch Seoul','Hàn Quốc Sun Group tham gia Seoul International Travel Fair (4-7/6) giới thiệu các điểm đến du lịch nổi tiếng của Việt Nam, đồng thời ưu đãi vé máy bay đến Phú Quốc cho khách tham quan.','https://vnexpress.net/sun-group-gioi-thieu-diem-den-viet-tai-hoi-cho-du-lich-seoul-5081847.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/04/sun-1780555561-8897-1780555580.png?w=240&h=144&q=100&dpr=1&fit=crop&s=RB48G-TbGdmxB-dsMrmHyQ','2026-06-05 15:08:40'),(2806,'https://vnexpress.net/ben-trong-hang-chua-hang-tram-ngoc-dong-o-phong-nha-ke-bang-5081563.html','Bên trong hang chứa hàng trăm ngọc động ở Phong Nha - Kẻ Bàng','Quảng Trị Hang Hùng thuộc hệ thống hang Hung Thoòng, nằm trong vùng lõi Vườn Quốc gia Phong Nha - Kẻ Bàng, chứa hàng trăm ngọc động và thạch nhũ với nhiều hình dáng, màu sắc.','https://vnexpress.net/ben-trong-hang-chua-hang-tram-ngoc-dong-o-phong-nha-ke-bang-5081563.html',NULL,'https://i1-vnexpress.vnecdn.net/2026/06/03/anh-1780497604.webp?w=240&h=144&q=100&dpr=1&fit=crop&s=LaOPGrUhBOWPL5DPeBVGrA','2026-06-05 15:08:40'),(2807,'https://vnexpress.net/cach-hang-hung-chua-ngoc-dong-duoc-khai-thac-du-lich-5081581.html','Cách hang Hùng chứa ngọc động được khai thác du lịch','Nằm trong vùng lõi Vườn quốc gia Phong Nha - Kẻ Bàng, hang Hùng thu hút sự chú ý với hàng trăm viên ngọc động, được đưa vào khai thác du lịch mạo hiểm có kiểm soát ba năm qua.','https://vnexpress.net/cach-hang-hung-chua-ngoc-dong-duoc-khai-thac-du-lich-5081581.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/03/anh1178047623124961780478780-1-7545-1440-1780482722.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=UNN4Q3FZAd2B2w8ilkVJtA','2026-06-05 15:08:40'),(2808,'https://vnexpress.net/phao-hoa-cach-sun-group-tao-suc-hut-cho-cac-diem-den-5081333.html','Pháo hoa - cách Sun Group tạo sức hút cho các điểm đến','Từ DIFF Đà Nẵng đến các show diễn tại Phú Quốc, các màn pháo hoa quy mô lớn cho thấy hướng đi khác biệt của Sun Group trong định vị thương hiệu quốc tế các điểm đến.','https://vnexpress.net/phao-hoa-cach-sun-group-tao-suc-hut-cho-cac-diem-den-5081333.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/03/phao-hoa-diff-1780477894-4476-1780477992.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=0OjMxcQIzqyFx8fgvAQPZw','2026-06-05 15:08:40'),(2809,'https://vnexpress.net/da-nang-vao-mua-du-lich-the-thao-5081152.html','Đà Nẵng vào mùa du lịch thể thao','VnExpress Marathon và Hoiana Aquaman 2026 dự kiến thu hút hàng chục nghìn VĐV, tạo không khí lễ hội và quảng bá du lịch của thành phố lớn nhất miền Trung.','https://vnexpress.net/da-nang-vao-mua-du-lich-the-thao-5081152.html',NULL,'https://i1-vnexpress.vnecdn.net/2026/06/03/519465354-n-1780454237-2001-1780457260.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=9Riag4NWSmdZw1xRvU9Ljw','2026-06-05 15:08:40'),(2810,'https://vnexpress.net/trai-tim-hoa-thuong-thich-quang-duc-duoc-dat-tai-chua-nao-5081138.html','Trái tim Hòa thượng Thích Quảng Đức được đặt tại chùa nào?','Ngôi chùa hơn 60 năm tại TP HCM là nơi tôn trí xá lợi trái tim Hòa thượng Thích Quảng Đức, sau hơn 34 năm được lưu giữ tại Ngân hàng Nhà nước chi nhánh TP HCM.','https://vnexpress.net/trai-tim-hoa-thuong-thich-quang-duc-duoc-dat-tai-chua-nao-5081138.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/02/traitimbotatthichquangdu302742-3890-7863-1780389377.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=6Ho5sXjYBnfMjCPt5ZbkRA','2026-06-05 15:08:40'),(2811,'https://vnexpress.net/4-trai-nghiem-mua-he-nen-thu-o-thai-nguyen-5078929.html','4 trải nghiệm mùa hè nên thử ở Thái Nguyên','Đi thuyền giữa hồ Ba Bể, trèo cây hái chè cổ thụ, nghe đàn tính là những trải nghiệm dành cho du khách tới Thái Nguyên dịp này.','https://vnexpress.net/4-trai-nghiem-mua-he-nen-thu-o-thai-nguyen-5078929.html',NULL,'https://i1-dulich.vnecdn.net/2026/05/27/705705629-n-1779879655.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=p4W1yNSc-Trp8BVYwS5TzA','2026-06-05 15:08:40'),(2812,'https://vnexpress.net/ten-goi-philippines-dat-theo-vua-nuoc-nao-5080654.html','Tên gọi Philippines đặt theo Vua nước nào?','Quần đảo Philippinnes có gần 8.000 đảo lớn nhỏ, nằm ở khu vực Đông Nam Á và được đặt tên theo tên Vua Philip II cai trị vào thế kỷ XVI.','https://vnexpress.net/ten-goi-philippines-dat-theo-vua-nuoc-nao-5080654.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/01/largecoronpalawanphilippinessh-1584-8951-1780303609.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=tocLIh5WBvGaWRT8pJ5o0g','2026-06-05 15:08:40'),(2813,'https://vnexpress.net/nam-quan-tai-trong-quan-bar-cua-nha-su-nhat-ban-5080719.html','Nằm quan tài trong quán bar của nhà sư Nhật Bản','Một quán bar tại Tokyo do các nhà sư trực tiếp pha chế và điều hành đang thu hút du khách nhờ sự kết hợp độc lạ giữa đồ uống có cồn, những bài tụng kinh và trải nghiệm cận tử.','https://vnexpress.net/nam-quan-tai-trong-quan-bar-cua-nha-su-nhat-ban-5080719.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/01/enjoying-a-drink-and-some-budd-3222-8856-1780304514.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=qMQ3BSS6QW6X3zE6OR_2uA','2026-06-05 15:08:40'),(2814,'https://vnexpress.net/ben-trong-toa-nha-dat-do-hang-dau-the-gioi-5078877.html','Bên trong toà nhà đắt đỏ hàng đầu thế giới','Khách sạn Wynn Las Vegas nằm ở phía bắc đại lộ Las Vegas Strip được đầu tư 2,7 tỷ USD vào năm 2005, nằm trong danh sách các toà nhà đắt đỏ hàng đầu thế giới.','https://vnexpress.net/ben-trong-toa-nha-dat-do-hang-dau-the-gioi-5078877.html',NULL,'https://i1-dulich.vnecdn.net/2026/05/27/Wynn-Casino-2018-Encore-Casino-no-top-palms-photo-by-Barbara-Kraft-1779871354.webp?w=240&h=144&q=100&dpr=1&fit=crop&s=5EtgQsSFW-G9oyZC0nz9BQ','2026-06-05 15:08:40'),(2815,'https://vnexpress.net/tiem-banh-danh-tieng-phap-ra-mat-tren-dinh-ba-na-5080762.html','Tiệm bánh danh tiếng Pháp ra mắt trên đỉnh Bà Nà','Đà Nẵng Tiệm bánh Eric Kayser - thương hiệu lâu đời của Pháp vừa mở cửa đón những vị khách đầu tiên tại khu du lịch Sun World Ba Na Hills.','https://vnexpress.net/tiem-banh-danh-tieng-phap-ra-mat-tren-dinh-ba-na-5080762.html',NULL,'https://i1-dulich.vnecdn.net/2026/06/01/2-1780309443.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=upODHEXgwJ4lDufv0X1uzQ','2026-06-05 15:08:40'),(2816,'https://vnexpress.net/ben-trong-bao-tang-vinh-danh-ong-vua-truyen-co-tich-andersen-5051946.html','Bên trong bảo tàng vinh danh \'ông vua truyện cổ tích\' Andersen','Đan Mạch Bên trong bảo tàng Hans Christian Andersen, thế giới cổ tích được tái hiện sống động qua không gian ngầm cùng công nghệ tương tác đa giác quan.','https://vnexpress.net/ben-trong-bao-tang-vinh-danh-ong-vua-truyen-co-tich-andersen-5051946.html',NULL,'https://i1-dulich.vnecdn.net/2026/03/18/DJI-0489-copy-1773819413.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=k1500R2NWrL3z-kHuDbxYw','2026-06-05 15:08:40'),(2817,'https://vnexpress.net/dalat-edensee-khu-nghi-duong-an-minh-ben-ho-tuyen-lam-5079785.html','Dalat Edensee - khu nghỉ dưỡng ẩn mình bên hồ Tuyền Lâm','Nép mình bên hồ Tuyền Lâm, Dalat Edensee mang đến không gian nghỉ dưỡng giữa rừng thông, cách trung tâm Đà Lạt khoảng 30 phút di chuyển.','https://vnexpress.net/dalat-edensee-khu-nghi-duong-an-minh-ben-ho-tuyen-lam-5079785.html',NULL,'https://i1-dulich.vnecdn.net/2026/05/31/thumbnail-1780235556-4743-1780235763.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=KppjBDzodLg3G6Bp_MiG8Q','2026-06-05 15:08:40'),(2818,'https://vnexpress.net/chua-nao-co-hang-nghin-con-doi-cu-tru-5080175.html','Chùa nào có hàng nghìn con dơi cư trú?','Bao quanh ngôi chùa 500 năm theo kiến trúc đặc trưng của người Khmer là rừng cây sao, dầu cổ thụ, nơi trú ẩn của đàn dơi.','https://vnexpress.net/chua-nao-co-hang-nghin-con-doi-cu-tru-5080175.html',NULL,'https://i1-dulich.vnecdn.net/2026/05/31/chuadoisoctrangvnexpress151582-4575-7695-1780161090.webp?w=240&h=144&q=100&dpr=1&fit=crop&s=2429Rw8bip3RFGjnDeI-1Q','2026-06-05 15:08:40'),(2819,'https://vnexpress.net/quan-ca-phe-thiet-ke-khong-gian-bang-do-da-5076887.html','Quán cà phê thiết kế không gian bằng đồ đá','Lạng Sơn Quán cà phê sử dụng hàng trăm phiến đá, đồ dùng sinh hoạt có tuổi đời lâu năm làm đồ trang trí, bàn ghế và lối đi cho khách.','https://vnexpress.net/quan-ca-phe-thiet-ke-khong-gian-bang-do-da-5076887.html',NULL,'https://i1-dulich.vnecdn.net/2026/05/31/ke4-1780224754.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=473OIRmj2TkD4UT7PjuNYQ','2026-06-05 15:08:40'),(2820,'https://vnexpress.net/ngoi-chua-trong-hem-trang-tri-hang-tram-tuong-rong-o-tp-hcm-5079664.html','Ngôi chùa trong hẻm trang trí hàng trăm tượng rồng ở TP HCM','Chùa Phật Bảo ở phường Minh Phụng có diện tích nhỏ, trang trí dày đặc hình tượng rồng, hiện do hai vị sư tu tập, trông coi.','https://vnexpress.net/ngoi-chua-trong-hem-trang-tri-hang-tram-tuong-rong-o-tp-hcm-5079664.html',NULL,'https://i1-dulich.vnecdn.net/2026/05/31/233a4274-1780202445.jpg?w=240&h=144&q=100&dpr=1&fit=crop&s=bx-v2pZSqalUl8GZy0ZmtQ','2026-06-05 15:08:40');
